#![forbid(unsafe_code)]

#[path = "emit_protocol_types/aliases.rs"]
mod aliases;
#[path = "emit_protocol_types/interfaces.rs"]
mod interfaces;

use aliases::aliases;
use interfaces::interfaces;

fn main() {
    print!("{}", render_api_types());
}

fn render_api_types() -> String {
    let mut out = String::from(
        "// GENERATED by rulebench-authority Rust protocol metadata. Do not hand-edit.\n\n",
    );
    for alias in aliases() {
        out.push_str(alias);
        out.push_str("\n\n");
    }
    for interface in interfaces() {
        out.push_str(&format!("export interface {} {{\n", interface.name));
        for field in interface.fields {
            out.push_str(&format!("  readonly {}: {};\n", field.name, field.ty));
        }
        out.push_str("}\n\n");
    }
    if out.ends_with("\n\n") {
        out.pop();
    }
    out
}
